class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int m = s1.size(), n = s2.size(), o = s3.size();
        int res = INT_MAX;
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                for (int k = 0; k <= o; k++) {
                    int op1 = i + j + k;
                    if (i > 0 && s1.substr(0, i) != s2.substr(0, i)) op1++;
                    if (i > 0 && s1.substr(0, i) != s3.substr(0, i)) op1++;
                    if (j > 0 && s2.substr(0, j) != s3.substr(0, j)) op1++;
                    res = min(res, op1);
                }
            }
        }
        return res == INT_MAX ? -1 : res;
    }
};
